import uuid
import pytest
from <api_client> import BankingApiClient

@pytest.fixture
def primary_client():
    return BankingApiClient(token=<primary_auth_token>)

def test_primary_holder_transaction_succeeds(primary_client):
    account_id = <JOINT_ACCOUNT_ID>
    idempotency_key = str(uuid.uuid4())
    payload = {"type": "debit", "amount": 100, "currency": "USD"}
    headers = {"Idempotency-Key": idempotency_key}

    resp = primary_client.post(
        f"/accounts/{account_id}/joint",
        json=payload,
        headers=headers
    )

    assert resp.status_code in (200, 201), f"Unexpected status: {resp.status_code}"
    body = resp.json()
    assert "transaction_id" in body
    assert body.get("status") == "applied"

import pytest
from <api_client> import BankingApiClient

@pytest.fixture
def secondary_client():
    return BankingApiClient(token=<secondary_auth_token>)

def test_secondary_holder_ownership_change_forbidden(secondary_client):
    account_id = <JOINT_ACCOUNT_ID>
    payload = {"primary_holder_id": <NEW_HOLDER_ID>}

    resp = secondary_client.patch(
        f"/accounts/{account_id}/joint",
        json=payload
    )

    assert resp.status_code == 403, f"Expected 403, got {resp.status_code}"
    body = resp.json()
    error_code = body.get("error", {}).get("code", "")
    assert "ownership" in error_code.lower() or resp.status_code == 403
